import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Rsvp, RsvpStatus } from '../../core/models';

/**
 * GatherUp "My Events" — the caller's RSVPs and their statuses.
 * Loads live via ApiService.myEvents() in ngOnInit().
 */
@Component({
  selector: 'app-my-events',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './my-events.component.html',
  styleUrl: './my-events.component.css',
})
export class MyEventsComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly rsvps = signal<Rsvp[]>([]);

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.myEvents().subscribe({
      next: (rsvps) => {
        this.rsvps.set(rsvps);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load your events. Please try again.');
        this.loading.set(false);
      },
    });
  }

  badge(status: RsvpStatus): { cls: string; label: string } {
    switch (status) {
      case 'confirmed': return { cls: 'badge-ok', label: 'Confirmed' };
      case 'checkedIn': return { cls: 'badge-info', label: 'Checked in' };
      case 'waitlist': return { cls: 'badge-warn', label: 'Waitlisted' };
      default: return { cls: 'badge-muted', label: 'Cancelled' };
    }
  }

  when(iso?: string): string {
    if (!iso) return '';
    return new Date(iso).toLocaleString(undefined, {
      weekday: 'short', month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit',
    });
  }
}
